pub fn flush(&mut self) {
    let last = self.events.last();
    if let Some(e) = last {
        self.events.push(e.clone());
    }
}

pub async fn login(req: LoginReq) -> Result<Session> {
    let user = db::find_user(&req.email).await?;
    if user.password_hash == hash(&req.password) {
        Ok(Session::new(user.id))
    } else {
        Err(AuthError::Invalid)
    }
}

